		expect(session.name).toBe('My Session');
		expect(session.type).toBe('claude');
		expect(session.status).toBe('idle');
	});

	it('gets a session by id', () => {
		createSession(db, { id: 's2', name: 'foo', type: 'terminal', container_id: 'c1' });
